import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box,
  Spacer,
  Icon,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

export default function GeneratedComponent({
  city = "San Francisco",
  temperature = 22,
  condition = "Partly Cloudy",
  humidity = 60,
  windSpeed = 12,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 25, low: 18 },
    { day: "Tue", icon: "⛅", high: 22, low: 16 },
    { day: "Wed", icon: "☁️", high: 20, low: 15 },
    { day: "Thu", icon: "🌧️", high: 18, low: 14 },
    { day: "Fri", icon: "⛅", high: 21, low: 16 },
  ],
}: Props) {
  const [hoverIndex, setHoverIndex] = useState<number | null>(null);

  // Simple emoji mapping for the main current condition icon
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud') || c.includes('partly')) return '⛅';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('storm')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    return '🌡️';
  };

  return (
    <div role="region" aria-label={`Weather information for ${city}`}>
      <Card
        shadow="md"
        padding={24}
        radius="xl"
        border={true}
        style={{
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          maxWidth: '400px',
          width: '100%',
        }}
      >
        {/* Header: City and Condition */}
        <Stack gap={4}>
          <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
            {city ?? "Unknown Location"}
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            {condition ?? "Condition unknown"}
          </Text>
        </Stack>

        <Spacer size={24} />

        {/* Main Temperature Display */}
        <Stack direction="horizontal" align="center" justify="between">
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature ?? 0}°{unit ?? "C"}
          </Text>
          <Box padding={8}>
            <Text size="4xl" style={{ lineHeight: 1 }}>
              {getConditionEmoji(condition ?? "")}
            </Text>
          </Box>
        </Stack>

        <Spacer size={24} />

        {/* Atmospheric Stats */}
        <Stack direction="horizontal" gap={32}>
          {/* Humidity Stat */}
          <Stack direction="horizontal" gap={8} align="center">
            <Icon
              name="menu"
              size={18}
              color="var(--ggui-color-primary-500, #0ea5e9)"
              aria-hidden="true"
            />
            <Stack gap={0}>
              <Text variant="overline" size="xs">HUMIDITY</Text>
              <Text weight="semibold" size="sm">
                {humidity ?? 0}%
              </Text>
            </Stack>
          </Stack>

          {/* Wind Stat */}
          <Stack direction="horizontal" gap={8} align="center">
            <Icon
              name="settings"
              size={18}
              color="var(--ggui-color-primary-500, #0ea5e9)"
              aria-hidden="true"
            />
            <Stack gap={0}>
              <Text variant="overline" size="xs">WIND</Text>
              <Text weight="semibold" size="sm">
                {windSpeed ?? 0} km/h
              </Text>
            </Stack>
          </Stack>
        </Stack>

        <Divider margin={20} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {(forecast ?? []).map((item, idx) => (
            <div
              key={`${item.day}-${idx}`}
              onMouseEnter={() => setHoverIndex(idx)}
              onMouseLeave={() => setHoverIndex(null)}
              style={{ flex: 1, minWidth: 0 }}
            >
              <Box
                padding={8}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  transition: 'background-color 200ms ease, transform 200ms ease',
                  backgroundColor: hoverIndex === idx 
                    ? 'var(--ggui-color-primary-50, #f0f9ff)' 
                    : 'transparent',
                  transform: hoverIndex === idx ? 'scale(1.05)' : 'scale(1)',
                  cursor: 'default',
                  textAlign: 'center'
                }}
              >
                <Stack align="center" gap={4}>
                  <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {item.day ?? 'Day'}
                  </Text>
                  <Text size="lg" style={{ lineHeight: 1 }}>
                    {item.icon ?? '🌡️'}
                  </Text>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold">
                      {item.high ?? 0}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.low ?? 0}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            </div>
          ))}
        </Stack>
      </Card>
    </div>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Box,
  Divider,
  Badge,
  Icon,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

export default function GeneratedComponent({
  city = 'Tokyo',
  temperature = 28,
  condition = 'Sunny',
  humidity = 45,
  windSpeed = 8,
  unit = 'C',
  forecast = [],
}: Props) {
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);

  return (
    <div
      role="region"
      aria-label={`Weather for ${city}`}
      style={{
        animation: 'ggui-fadeIn 500ms ease-out both',
        width: '100%',
        maxWidth: '500px',
        margin: '0 auto',
      }}
    >
      <Card shadow="md" padding={24} radius="xl" border={true}>
        <Stack gap={24}>
          {/* Header Section */}
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={4}>
              <Heading level={2} color="var(--ggui-color-onSurface)">
                {city ?? 'Unknown'}
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Today&apos;s Forecast
              </Text>
            </Stack>
            <Badge variant="primary" size="lg">
              {condition ?? 'Clear'}
            </Badge>
          </Stack>

          {/* Hero Section */}
          <Stack align="center" justify="center" gap={0}>
            <div style={{ display: 'flex', alignItems: 'flex-start' }}>
              <span
                style={{
                  fontSize: '4rem',
                  fontWeight: 'var(--ggui-font-weight-bold, 700)',
                  color: 'var(--ggui-color-primary-600, #0284c7)',
                  lineHeight: '1',
                }}
              >
                {temperature ?? 0}
              </span>
              <Text
                size="2xl"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
                style={{ marginTop: '0.5rem' }}
              >
                °{unit ?? 'C'}
              </Text>
            </div>
            <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurfaceVariant)">
              {condition ?? 'Unknown'}
            </Text>
          </Stack>

          {/* Metrics Section */}
          <Stack direction="horizontal" justify="evenly" gap={16}>
            <Stack align="center" gap={4}>
              <Icon name="settings" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
              <Text variant="label" color="var(--ggui-color-onSurface)">
                {humidity ?? 0}%
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Humidity
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={8} />
            <Stack align="center" gap={4}>
              <Icon name="plus" size={20} color="var(--ggui-color-primary-500, #0ea5e9)" />
              <Text variant="label" color="var(--ggui-color-onSurface)">
                {windSpeed ?? 0} km/h
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Wind
              </Text>
            </Stack>
          </Stack>

          <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

          {/* Forecast Section */}
          <div
            style={{
              display: 'flex',
              gap: 'var(--ggui-spacing-2, 8px)',
              overflowX: 'auto',
              paddingBottom: '4px',
            }}
          >
            {forecast?.map((item, index) => (
              <div
                key={`${item.day}-${index}`}
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
                style={{
                  flex: '1',
                  minWidth: '70px',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  backgroundColor:
                    hoveredIndex === index
                      ? 'var(--ggui-color-primary-50, #f0f9ff)'
                      : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-2, 8px)',
                  transition: 'background-color 200ms ease-in-out',
                  cursor: 'default',
                  animation: `ggui-slideInUp 300ms ease-out ${index * 50}ms both`,
                  border: `1px solid ${
                    hoveredIndex === index
                      ? 'var(--ggui-color-primary-200, #bae6fd)'
                      : 'transparent'
                  }`,
                }}
              >
                <Stack align="center" gap={8}>
                  <Text
                    variant="overline"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {item.day ?? 'Day'}
                  </Text>
                  <span style={{ fontSize: '1.5rem' }}>{item.icon ?? '☀️'}</span>
                  <Stack gap={0} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurface)">
                      {item.high ?? 0}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                      {item.low ?? 0}°
                    </Text>
                  </Stack>
                </Stack>
              </div>
            ))}
          </div>
        </Stack>
      </Card>
    </div>
  );
}

