import React from 'react';
import { Card, Stack, Heading, Text, Divider, MotionKeyframes } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day?: string;
  icon?: string;
  high?: number;
  low?: number;
}

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: ForecastItem[];
}

/**
 * WeatherCard Component
 * Displays current weather conditions and a 5-day forecast in a structured dashboard layout.
 */
export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = []
}: Props) {
  const [isHovered, setIsHovered] = React.useState(false);

  // Map condition to a prominent emoji or fallback
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sunny') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    return '⛅';
  };

  const cardStyle = {
    backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    transition: 'transform 200ms ease-in-out, box-shadow 200ms ease-in-out',
    transform: isHovered ? 'translateY(-2px)' : 'translateY(0)',
    animation: 'ggui-fadeIn 200ms ease-out forwards',
    cursor: 'default'
  };

  return (
    <div 
      role="region" 
      aria-label={`Weather in ${city}`}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <MotionKeyframes />
      <Card 
        shadow="md" 
        radius="lg" 
        padding={24}
        style={cardStyle}
      >
        <Stack gap={24}>
          {/* Header Section */}
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city ?? 'Unknown City'}
            </Heading>
            <Text size="4xl" aria-hidden="true">
              {getConditionEmoji(condition)}
            </Text>
          </Stack>

          {/* Primary Data Section */}
          <Stack gap={4}>
            <Text 
              size="4xl" 
              weight="bold" 
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {temperature ?? 0}°{unit ?? 'C'}
            </Text>
            <Text 
              variant="bodyLarge" 
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition ?? 'Unknown'}
            </Text>
          </Stack>

          {/* Metrics Grid */}
          <Stack direction="horizontal" gap={32} align="center">
            {/* Humidity Group */}
            <Stack gap={4}>
              <Text 
                variant="caption" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {humidity ?? 0}%
              </Text>
            </Stack>

            {/* Wind Group */}
            <Stack gap={4}>
              <Text 
                variant="caption" 
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed ?? 0} km/h
              </Text>
            </Stack>
          </Stack>

          {/* 5-Day Forecast Section */}
          {(forecast && forecast.length > 0) && (
            <Stack gap={0}>
              <Divider 
                margin={16} 
                color="var(--ggui-color-outlineVariant, #e4e4e7)" 
              />
              <Stack direction="horizontal" justify="between" align="center">
                {forecast.map((item, index) => (
                  <Stack key={index} align="center" gap={8}>
                    <Text 
                      variant="caption" 
                      weight="semibold" 
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {item.day ?? '---'}
                    </Text>
                    <Text size="lg" aria-hidden="true">
                      {item.icon ?? '☁️'}
                    </Text>
                    <Stack direction="horizontal" gap={4}>
                      <Text 
                        variant="caption" 
                        weight="bold" 
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        {item.high ?? 0}°
                      </Text>
                      <Text 
                        variant="caption" 
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      >
                        {item.low ?? 0}°
                      </Text>
                    </Stack>
                  </Stack>
                ))}
              </Stack>
            </Stack>
          )}
        </Stack>
      </Card>
    </div>
  );
}
